export.skill:
{
  "id": "ljs",
  "description": "{This skill provides an interface for a Keyence scanner,
                    generating two files for each scan: one containing depth data and one containing luminance data.",
  "version": "1.0.0",
  "interface": "action",
  "default_interface_path": "/skill/ljs",
  "datatype": "ljs_skill_msgs/action/Ljs",
  "parameters": {
    "in": [
      {
      "name": "scan_id",
      "type": "string",
      "description": "This parameter uniquely identifies the object to be scanned."
      }
      {
      "name": "face_id",
      "type": "int8",
      "description": "This parameter uniquely identifies the side of the object to be scanned."
      },
  ]
   "out": [
      {
      "name": "result",
      "type": "int64",
      "description": "This parameter represents the result and enables specifying various types of success and failure." },
  ]
  },
  "functional_domains": [
      "perception"
  ]
}
